function sparkline(e){const s=e.slice(-60).map(e=>e.close).filter(e=>null!=e);if(s.length<2)return"";const a=Math.min(...s),t=Math.max(...s)-a||1,i=s.map((e,i)=>`${i/(s.length-1)*600},${84-(e-a)/t*76-4}`).join(" ");return`<svg class="sparkline" viewBox="0 0 600 84" preserveAspectRatio="none"><polygon class="area" points="${`0,84 ${i} 600,84`}"></polygon><polyline points="${i}"></polyline></svg>`}function probabilitySection(e){return`<div class="prob-grid"><div class="prob-box"><small class="muted">上漲機率</small><b class="up">${e.up}%</b><div class="progress"><span class="bar-up" style="width:${e.up}%"></span></div></div><div class="prob-box"><small class="muted">震盪機率</small><b class="neutral">${e.neutral}%</b><div class="progress"><span class="bar-neutral" style="width:${e.neutral}%"></span></div></div><div class="prob-box"><small class="muted">下跌機率</small><b class="down">${e.down}%</b><div class="progress"><span class="bar-down" style="width:${e.down}%"></span></div></div></div>`}function factorSection(e){return`<div class="factor-list">${[["技術面",e.technical,55],["基本面",e.fundamental,35],["籌碼面",e.chip,20],["估值面",e.valuation,15]].map(([e,s,a])=>`<div class="factor"><span>${e}</span><div class="track"><span style="width:${clamp((s+a)/(2*a)*100,0,100)}%"></span></div><b class="${cls(s)}">${s>0?"+":""}${fmt(s,1)}</b></div>`).join("")}</div>`}function scenarioHtml(e,s,a){return scenarioAnalysis(e,s,a).map(e=>`<div class="card scenario ${e.type}"><div class="head"><div><b>${e.title}</b><div class="muted">觸發條件：${e.trigger}</div></div><b>${e.prob}%</b></div><div class="price">${fmt(e.range[0])}～${fmt(e.range[1])}</div><div class="muted">5 個交易日情境區間，非價格保證。</div></div>`).join("")}function marketIndustryHtml(e){const s=marketEnvironment(),a=s.industries.find(s=>s.industry===e.industry);return`<div class="grid">${metric("大盤環境",s.label)}${metric("多頭家數比",`${fmt(s.breadth,0)}%`)}${metric(`${e.industry}平均漲跌`,a?pct(a.avgChange):reasonDash("同業不足"))}${metric(`${e.industry}上漲家數`,a?`${fmt(a.breadth,0)}%`:reasonDash("同業不足"))}${metric("市場外資合計",`${fmt(s.foreign,0)} 張`)}${metric("產業外資合計",a?`${fmt(a.foreign,0)} 張`:reasonDash("同業不足"))}</div>`}function peerHtml(e){const s=peerComparison(e);return`<div class="card"><div class="muted">比較群組：${e.industry}，共 ${s.peerCount} 檔可比較股票</div>${s.rows.map(e=>`<div class="peer-row"><span>${e.label}</span><div><div class="peer-track"><span style="width:${e.percentile??0}%"></span></div><small class="muted">同業中位數 ${null==e.median?"—":`${fmt(e.median)}${e.suffix}`}</small></div><b>${null==e.value?"—":`${fmt(e.value)}${e.suffix}`}<br><small class="muted">前 ${null==e.percentile?"—":100-e.percentile+1}%</small></b></div>`).join("")}</div>`}function eventHtml(e,s){return`<div class="card">${buildEvents(e,s).map(e=>`<div class="event"><div class="event-icon">${e.icon}</div><div><b>${e.title}</b><div class="muted">${e.detail}</div></div><span class="tag ${"bad"===e.level?"bad":"warn"===e.level?"warn":"info"}">${"bad"===e.level?"風險":"warn"===e.level?"注意":"事件"}</span></div>`).join("")}</div>`}function detailHtml(e,s){const a=s?.indicators||null,t=s?.rows||[],i=calculateForecast(e,a),l=s?.loading,n=s?.error;return`<div class="modal"><div class="sheet"><button class="sheet-close" type="button">×</button><div class="head"><div><h2>${e.name} ${e.symbol}</h2><div class="muted">${e.market} · ${e.industry} · ${S.date}</div></div><button class="btn secondary small-btn" data-watch="${e.symbol}">${isWatched(e.symbol)?"★ 已自選":"☆ 加入自選"}</button></div><div><span class="price">${fmt(e.close)} 元</span> <b class="${cls(e.change)}">${pct(e.change)}</b></div>\n  ${l?'<div class="card"><div class="loading"><span class="spinner"></span>正在讀取歷史日線並計算技術指標…</div></div>':""}${n?`<div class="card warn-card"><b>歷史日線暫時無法取得</b><p class="muted">目前先使用基本面與籌碼進行低信心估計。${esc(n)}</p></div>`:""}${t.length?sparkline(t):""}\n  <h3 class="section-title">未來漲跌預測（5 個交易日）</h3><div class="card accent"><div class="head"><div><small class="muted">判斷</small><div class="price">${i.shortLabel}</div><div class="muted">中期：${i.mediumLabel}</div></div><div><small class="muted">預測信心</small><div class="score">${i.confidence}%</div><div class="muted">資料完整度 ${i.completeness}%</div></div></div>${probabilitySection(i)}<div class="grid" style="margin-top:10px">${metric("5 日合理波動區間",`${fmt(i.expectedLow)}～${fmt(i.expectedHigh)}`,`推估 ±${fmt(i.expectedMove5,1)}%`)}${metric("綜合方向分數",`${i.composite>0?"+":""}${i.composite}`,"正值偏多、負值偏空")}</div></div><div class="notice"><b>僅供參考使用</b><br>${DISCLAIMER}</div>\n  <h3 class="section-title">三種情境分析</h3>${scenarioHtml(e,i,a)}\n  <h3 class="section-title">大盤與產業環境</h3><div class="card">${marketIndustryHtml(e)}</div>\n  <h3 class="section-title">同業比較</h3>${peerHtml(e)}\n  <h3 class="section-title">重要事件與風險提醒</h3>${eventHtml(e,a)}\n  <h3 class="section-title">評估構成</h3><div class="card">${factorSection(i)}</div><div class="card"><h3>支持因素</h3>${i.positive.length?i.positive.map(e=>`<span class="tag">${e}</span>`).join(""):'<span class="muted">目前沒有明顯正向訊號</span>'}<h3 style="margin-top:14px">風險因素</h3>${i.negative.length?i.negative.map(e=>`<span class="tag warn">${e}</span>`).join(""):'<span class="muted">目前沒有明顯負向訊號</span>'}<h3 style="margin-top:14px">資料缺口</h3>${i.missing.length?i.missing.map(e=>`<span class="tag bad">${e}</span>`).join(""):'<span class="tag">主要資料完整</span>'}</div>\n  <h3 class="section-title">技術面分析</h3><div class="grid three">${metric("MA5",valueOrReason(a?.ma5))}${metric("MA20",valueOrReason(a?.ma20))}${metric("MA60",valueOrReason(a?.ma60))}${metric("RSI 14",valueOrReason(a?.rsi14))}${metric("MACD",valueOrReason(a?.macd))}${metric("MACD 柱狀體",valueOrReason(a?.histogram))}${metric("ATR 14",valueOrReason(a?.atr14),null!=a?.atrPct?`${fmt(a.atrPct)}%`:"")}${metric("量能比 5/20",valueOrReason(a?.volumeRatio," 倍"))}${metric("20 日動能",valueOrReason(a?.momentum20,"%"))}${metric("布林上軌",valueOrReason(a?.bollingerUpper))}${metric("布林中軌",valueOrReason(a?.bollingerMiddle))}${metric("布林下軌",valueOrReason(a?.bollingerLower))}${metric("20 日支撐",valueOrReason(a?.support))}${metric("20 日壓力",valueOrReason(a?.resistance))}${metric("歷史日線筆數",null==a?.rows?reasonDash("尚未取得"):fmt(a.rows,0))}</div>\n  <h3 class="section-title">基本面與估值</h3><div class="grid three">${metric("本益比",valueOrReason(e.pe))}${metric("股價淨值比",valueOrReason(e.pb))}${metric("殖利率",valueOrReason(e.yield,"%"))}${metric("當月營收",null==e.revenue?reasonDash("API 未回傳"):`${fmt(e.revenue/1e3,0)} 百萬元`,e.revPeriod||"")}${metric("月營收年增",pct(e.rev))}${metric("月營收月增",pct(e.revMom))}${metric("累計營收年增",pct(e.revYtd))}${metric("EPS",valueOrReason(e.eps))}${metric(e.roeEstimated?"年化推估 ROE":"ROE",valueOrReason(e.roe,"%"),e.roePeriod||"")}${metric("毛利率",valueOrReason(e.grossMargin,"%"))}${metric("營業利益率",valueOrReason(e.operatingMargin,"%"))}${metric("淨利率",valueOrReason(e.netMargin,"%"))}${metric("負債比",valueOrReason(e.debt,"%"))}${metric("權益比率",valueOrReason(e.equityRatio,"%"))}${metric("資料期間",e.roePeriod||e.revPeriod||"—")}</div>${e.roeEstimated?'<div class="notice">ROE 是依最新公開累計淨利與股東權益推算的年化值，並非官方直接公布的單一指標。</div>':""}\n  <h3 class="section-title">籌碼與交易資訊</h3><div class="grid three">${metric("外資買賣超",null==e.foreign?reasonDash("當日 API 無資料"):`${fmt(e.foreign,0)} 張`)}${metric("投信買賣超",null==e.trust?reasonDash("當日 API 無資料"):`${fmt(e.trust,0)} 張`)}${metric("自營商買賣超",null==e.dealer?reasonDash("當日 API 無資料"):`${fmt(e.dealer,0)} 張`)}${metric("三大法人合計",null==e.inst?reasonDash("當日 API 無資料"):`${fmt(e.inst,0)} 張`)}${metric("融資增減",null==e.marginChange?reasonDash("API 未回傳"):`${fmt(e.marginChange,0)} 張`)}${metric("融資餘額",null==e.marginBalance?reasonDash("API 未回傳"):`${fmt(e.marginBalance,0)} 張`)}${metric("融券增減",null==e.shortChange?reasonDash("API 未回傳"):`${fmt(e.shortChange,0)} 張`)}${metric("融券餘額",null==e.shortBalance?reasonDash("API 未回傳"):`${fmt(e.shortBalance,0)} 張`)}${metric("成交量",null==e.volume?reasonDash("API 未回傳"):`${fmt(e.volume,0)} 張`)}${metric("開盤",valueOrReason(e.open))}${metric("最高",valueOrReason(e.high))}${metric("最低",valueOrReason(e.low))}${metric("成交金額",null==e.value?reasonDash("API 未回傳"):`${fmt(e.value/1e8,2)} 億元`)}${metric("成交筆數",null==e.transactions?reasonDash("API 未回傳"):fmt(e.transactions,0))}${metric("收盤",valueOrReason(e.close))}</div>\n  <div class="row" style="margin-top:16px"><button class="btn grow" data-journal-stock="${e.symbol}">新增投資紀錄</button><button class="btn secondary" data-verify-stock="${e.symbol}">查看預測驗證</button></div>${disclaimer()}</div></div>`}async function openDetail(e,s=!0){const a=S.stocks.find(s=>s.symbol===e);if(!a)return;S.detailSymbol=e;const t=S.historyCache.get(e),i=!t||t instanceof Promise?null:t;if(modalRoot.innerHTML=detailHtml(a,i?{...i,loading:!1}:{loading:s,rows:[]}),bindModal(),s||t){if(i){const s=calculateForecast(a,i.indicators);return recordPrediction(a,s),void evaluatePredictionsForSymbol(e,i.rows)}try{const s=await getHistory(e);if(S.detailSymbol!==e)return;modalRoot.innerHTML=detailHtml(a,{...s,loading:!1}),bindModal();const t=calculateForecast(a,s.indicators);recordPrediction(a,t),evaluatePredictionsForSymbol(e,s.rows)}catch(s){if(S.detailSymbol!==e)return;modalRoot.innerHTML=detailHtml(a,{loading:!1,error:s.message,rows:[]}),bindModal(),recordPrediction(a,calculateForecast(a,null))}}}function closeModal(){S.detailSymbol=null,modalRoot.innerHTML=""}